        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                if (gcd(currentNums[i], currentNums[j]) === p) {
                    return true;
                }
            }
        }

        return false;
    };

    // Process queries
    for (const query of queries) {
        const [index, newValue] = query;

        // Perform update
        nums[index] = newValue;

        // Check condition after update
